parameters.jsCode:
const body = $input.first().json.body;

return [{
  json: {
    agent_name:          body.agent_name          || '',
    agent_email:         body.agent_email         || '',
    agent_phone:         body.agent_phone         || '',
    property_address:    body.property_address    || '',
    listing_description: body.listing_description || '',
  }
}];

const response = $input.first().json;
const highlights = (response.content[0].text || '').trim();

const prev = $('Prep Fields').first().json;

const baseUrl = 'https://tools.norrai.co/open_house.html';
const qs = [
  'address='     + encodeURIComponent(prev.property_address),
  'agent='       + encodeURIComponent(prev.agent_name),
  'agent_email=' + encodeURIComponent(prev.agent_email),
  'agent_phone=' + encodeURIComponent(prev.agent_phone),
  'notes='       + encodeURIComponent(highlights),
].join('&');
const signinUrl = baseUrl + '?' + qs;
const qrUrl = 'https://api.qrserver.com/v1/create-qr-code/?size=400x400&margin=2&data=' + encodeURIComponent(signinUrl);

// Escape & in URLs used inside HTML attributes
const qrUrlSafe     = qrUrl.replace(/&/g, '&amp;');
const signinUrlSafe = signinUrl.replace(/&/g, '&amp;');

const emailHtml = [
  '<div style="font-family: \'Inter\', Arial, sans-serif; max-width: 520px; margin: 0 auto; color: #0A0F1A;">',
  '  <div style="background: #0A0F1A; padding: 32px 32px 28px; border-radius: 8px 8px 0 0;">',
  '    <p style="font-size: 11px; letter-spacing: 0.15em; text-transform: uppercase; color: #7FA9B8; margin: 0 0 10px;">Open House Setup</p>',
  '    <h1 style="font-size: 22px; font-weight: 700; color: #FAFAF7; margin: 0; letter-spacing: -0.02em;">Your QR code is ready.</h1>',
  '  </div>',
  '  <div style="background: #FFFFFF; padding: 32px; border: 1px solid #E5E4DE; border-top: none; border-radius: 0 0 8px 8px;">',
  '    <p style="font-size: 14px; color: #3A3F48; margin: 0 0 6px;">Property</p>',
  '    <p style="font-size: 16px; font-weight: 600; color: #0A0F1A; margin: 0 0 24px;">' + prev.property_address + '</p>',
  '    <p style="font-size: 14px; color: #6A6F78; margin: 0 0 16px;">Print this and tape it to the front door. Attendees scan it to sign in \u2014 you\'ll get a personalized follow-up sent to each of them at 9am the next morning.</p>',
  '    <div style="text-align: center; margin: 28px 0;">',
  '      <img src="' + qrUrlSafe + '" width="300" height="300" alt="Open House Sign-In QR Code" style="display: inline-block; border: 1px solid #E5E4DE; border-radius: 8px; padding: 12px; background: #fff;">',
  '    </div>',
  '    <p style="font-size: 12px; color: #9EA3AA; margin: 0 0 6px;">Property highlights Claude will reference in follow-ups:</p>',
  '    <p style="font-size: 13px; color: #3A3F48; font-style: italic; margin: 0 0 24px; padding: 12px 14px; background: #FAFAF7; border-radius: 6px; border: 1px solid #E5E4DE;">' + highlights + '</p>',
  '    <p style="font-size: 12px; color: #9EA3AA; margin: 0 0 6px;">Direct link (if you need to share digitally):</p>',
  '    <p style="font-size: 12px; margin: 0 0 28px; word-break: break-all;"><a href="' + signinUrlSafe + '" style="color: #7FA9B8;">' + signinUrl + '</a></p>',
  '    <hr style="border: none; border-top: 1px solid #E5E4DE; margin: 0 0 20px;">',
  '    <p style="font-size: 12px; color: #9EA3AA; margin: 0;">Norr AI &nbsp;\u00b7&nbsp; <a href="https://norrai.co" style="color: #9EA3AA;">norrai.co</a></p>',
  '  </div>',
  '</div>',
].join('\n');

return [{
  json: {
    highlights,
    signin_url:       signinUrl,
    qr_url:           qrUrl,
    agent_name:       prev.agent_name,
    agent_email:      prev.agent_email,
    property_address: prev.property_address,
    email_html:       emailHtml,
  }
}];

